import{_ as o,o as a,c,a3 as d}from"./chunks/framework.aYYe0dfI.js";const p=JSON.parse('{"title":"Module extract:merge","description":"该模块负责将多个来源的符号提取结果合并到统一的模型表示中。它公开发布了 merge_symbol_info、rebuild_model_indexes 和 rebuild_lookup_maps 等核心函数，用于将传入的符号信息整合到目标模型内，并重建内部索引与查找映射以保持查询逻辑的一致性。此外，模块还提供了 append_unique、append_unique_range 和 deduplicate 等辅助模板变量，用于处理容器中元素的去重追加，以及 LocalIndexData 结构体以支持并行环境下的局部索引构建。整体上，该模块是提取流水线的关键组成部分，在 config、extract:filter 与 extract:model 等模块的基础上，实现了从原始提取数据到可查询模型状态的转换。","frontmatter":{"title":"Module extract:merge","description":"该模块负责将多个来源的符号提取结果合并到统一的模型表示中。它公开发布了 merge_symbol_info、rebuild_model_indexes 和 rebuild_lookup_maps 等核心函数，用于将传入的符号信息整合到目标模型内，并重建内部索引与查找映射以保持查询逻辑的一致性。此外，模块还提供了 append_unique、append_unique_range 和 deduplicate 等辅助模板变量，用于处理容器中元素的去重追加，以及 LocalIndexData 结构体以支持并行环境下的局部索引构建。整体上，该模块是提取流水线的关键组成部分，在 config、extract:filter 与 extract:model 等模块的基础上，实现了从原始提取数据到可查询模型状态的转换。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/modules/extract/merge.md","filePath":"zh/clore/modules/extract/merge.md"}'),r={name:"zh/clore/modules/extract/merge.md"};function t(l,e,i,n,s,u){return a(),c("div",null,[...e[0]||(e[0]=[d("",84)])])}const h=o(r,[["render",t]]);export{p as __pageData,h as default};
